#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[200001], B[200001], C[200001];
        scanf("%s %s %s", A, B, C);
        int lenA = strlen(A), lenB = strlen(B), lenC = strlen(C);
        int minLen = lenA + lenB + lenC;
        for (int i = 0; i <= lenA + lenB; i++) {
            for (int j = 0; j <= lenA + lenB; j++) {
                char temp[400002];
                strcpy(temp, A);
                strcat(temp, B);
                if (i > 0) {
                    temp[i] = '0';
                    strcat(temp, C);
                    strcat(temp, B);
                }
                if (strstr(temp, C) != NULL) {
                    minLen = (minLen < strlen(temp)) ? minLen : strlen(temp);
                }
            }
        }
        printf("%d\n", minLen);
    }
    return 0;
}

